INSERT INTO facts (title, content, category, order_index, source_url) VALUES
('Two-tier to unitary restructuring', '<p>Local government reorganisation in England often involves moving from a two-tier system (county and district councils) to single-tier unitary authorities, simplifying governance and accountability.</p>', 'Overview', 0, NULL),
('Staff transfer and TUPE', '<p>When councils merge or restructure, staff typically transfer under TUPE regulations, protecting terms and conditions and ensuring continuity of service delivery during transition.</p>', 'Workforce Impact', 1, NULL),
('Revenue and cost implications', '<p>Reorganisation can generate revenue savings through back-office consolidation and economies of scale, but upfront transition costs and redundancy payments must be planned for.</p>', 'Financial Performance', 2, NULL),
('Service continuity during transition', '<p>Shadow authorities and implementation teams work to maintain service continuity so residents experience minimal disruption during the reorganisation period.</p>', 'Service Delivery', 3, NULL),
('Councillor numbers and representation', '<p>Unitary reorganisation usually reduces the total number of councillors, affecting democratic representation and the ratio of representatives to residents.</p>', 'Democratic Impact', 4, NULL),
('Boundary and identity considerations', '<p>New unitary boundaries may align with historic counties or combine districts; community identity and local ties are often part of the debate.</p>', 'Overview', 5, NULL),
('Redundancy and redeployment', '<p>Workforce plans typically include voluntary redundancy schemes and redeployment to minimise compulsory job losses while aligning roles to the new structure.</p>', 'Workforce Impact', 6, NULL),
('Capital and transition funding', '<p>Central government has provided transition funding for some reorganisations; business cases often reference capital requirements for IT and property.</p>', 'Financial Performance', 7, NULL),
('Integration of services', '<p>Service integration across former districts or county and districts can improve coordination in areas such as planning, transport, and adult social care.</p>', 'Service Delivery', 8, NULL),
('Election cycles and shadow authorities', '<p>Shadow authorities are usually elected before vesting day, allowing a run-in period to prepare for the new council and set priorities.</p>', 'Democratic Impact', 9, NULL),
('Scale and capacity of unitaries', '<p>Unitary authorities are often larger in population and budget than the districts they replace, with potential for greater strategic capacity and influence.</p>', 'Overview', 10, NULL),
('Trade union engagement', '<p>Effective reorganisation programmes involve early engagement with trade unions and staff representatives on workforce and organisational design.</p>', 'Workforce Impact', 11, NULL),
('Revenue savings projections', '<p>Business cases for reorganisation typically include projected annual revenue savings, often from shared services and reduced senior management.</p>', 'Financial Performance', 12, NULL),
('Customer access and channels', '<p>Unitary councils can offer a single point of contact for residents, simplifying access to services and reducing confusion between tiers.</p>', 'Service Delivery', 13, NULL),
('Local committees and devolution', '<p>Some unitaries establish area committees or devolved arrangements to retain local decision-making and engagement within the larger structure.</p>', 'Democratic Impact', 14, NULL),
('Government policy and invitations', '<p>Reorganisation in England is often driven by government invitations or criteria; recent waves have focused on areas that propose unitary or combined authority models.</p>', 'Overview', 15, NULL),
('Skills and capability planning', '<p>Workforce planning during reorganisation includes assessing skills gaps and training needs for the new organisation and revised roles.</p>', 'Workforce Impact', 16, NULL),
('One-off transition costs', '<p>Transition costs include redundancy, IT migration, rebranding, and legal and consultancy fees; these are often front-loaded in the first few years.</p>', 'Financial Performance', 17, NULL),
('Waste and environment services', '<p>Waste collection and disposal, and other environment services, are commonly consolidated at unitary level, affecting contracts and delivery models.</p>', 'Service Delivery', 18, NULL),
('Voting and electoral arrangements', '<p>New unitaries adopt electoral arrangements (whole-council or by-thirds elections, ward boundaries) that affect political balance and continuity.</p>', 'Democratic Impact', 19, NULL),
('Timeline from proposal to vesting', '<p>Reorganisation timelines from government decision to vesting day typically span several years, allowing for shadow authority, staffing, and system transition.</p>', 'Overview', 20, NULL),
('Chief officer and senior structure', '<p>Senior management structures are redesigned in a unitary, usually with one chief executive and a reduced number of directors covering all services.</p>', 'Workforce Impact', 21, NULL),
('Council tax harmonisation', '<p>Where former districts had different council tax levels, the new unitary may harmonise rates over a transition period, with implications for residents.</p>', 'Financial Performance', 22, NULL),
('Children''s and adult social care', '<p>Social care services are often brought under one authority in a unitary, enabling integrated commissioning and delivery with health partners.</p>', 'Service Delivery', 23, NULL),
('Parish and town councils', '<p>Parish and town councils continue below unitary level; their role in local identity and minor services can become more prominent post-reorganisation.</p>', 'Democratic Impact', 24, NULL),
('Evidence from past reorganisations', '<p>Evidence from previous unitary transitions in England informs business cases and lessons learned on finance, workforce, and service delivery.</p>', 'Overview', 25, NULL),
('Pension and employment continuity', '<p>Local government pension arrangements and employment rights are maintained through transfer schemes and TUPE when staff move to the new authority.</p>', 'Workforce Impact', 26, NULL),
('Reserves and financial resilience', '<p>Authorities plan use of reserves and cash flow to cover transition costs while maintaining financial resilience and balanced budgets.</p>', 'Financial Performance', 27, NULL),
('Housing and planning', '<p>Planning and housing functions are consolidated in a unitary, enabling a single local plan and a more coherent approach to housing delivery.</p>', 'Service Delivery', 28, NULL),
('Scrutiny and governance', '<p>Unitary councils establish scrutiny committees and governance arrangements to hold the executive to account and engage with communities.</p>', 'Democratic Impact', 29, NULL),
('Stakeholder and partner engagement', '<p>Reorganisation programmes engage with residents, businesses, health bodies, and voluntary sector to align priorities and communication.</p>', 'Overview', 30, NULL),
('Change management and communication', '<p>Internal change management and staff communication are critical to maintain morale and productivity during the transition period.</p>', 'Workforce Impact', 31, NULL),
('Efficiency and transformation programmes', '<p>Transformation programmes often run alongside reorganisation to deliver savings and service improvements in the new structure.</p>', 'Financial Performance', 32, NULL),
('Highways and transport', '<p>Highways and transport strategy can be delivered at unitary level, aligning with planning and economic development in a single authority.</p>', 'Service Delivery', 33, NULL),
('Community engagement and consultation', '<p>Consultation on reorganisation and on the new council''s priorities helps shape governance and service design and build legitimacy.</p>', 'Democratic Impact', 34, NULL),
('Legal and constitutional basis', '<p>Reorganisation is implemented under the Local Government and Public Involvement in Health Act 2007 and related secondary legislation.</p>', 'Overview', 35, NULL),
('HR and payroll integration', '<p>HR and payroll systems are merged in the new authority, requiring careful data migration and alignment of policies and terms.</p>', 'Workforce Impact', 36, NULL),
('Audit and assurance', '<p>Auditors and scrutiny provide assurance on the financial and governance aspects of the transition and the new authority.</p>', 'Financial Performance', 37, NULL),
('Leisure and culture', '<p>Leisure, culture, and heritage services may be consolidated or delivered in partnership across the new unitary area.</p>', 'Service Delivery', 38, NULL),
('Leader and cabinet model', '<p>Most unitary councils in England operate a leader and cabinet executive model, with full council setting the budget and policy framework.</p>', 'Democratic Impact', 39, NULL),
('Regional and national context', '<p>Reorganisation takes place in a context of devolution, combined authorities, and national funding changes that affect local government.</p>', 'Overview', 40, NULL),
('Retention and recruitment', '<p>Retention of key staff and recruitment to new roles are managed during transition to ensure the new organisation is ready for vesting day.</p>', 'Workforce Impact', 41, NULL),
('Revenue support and grants', '<p>Funding arrangements for the new authority, including revenue support and specific grants, are set by government as part of the reorganisation.</p>', 'Financial Performance', 42, NULL),
('Public health', '<p>Public health responsibilities sit with the unitary council, enabling joined-up action on prevention and health inequalities across the area.</p>', 'Service Delivery', 43, NULL),
('Mayors and devolution', '<p>Some areas have combined authority mayors or other devolution deals alongside or instead of unitary reorganisation.</p>', 'Democratic Impact', 44, NULL),
('Lessons from implementation', '<p>Post-implementation reviews and lessons learned from earlier unitaries inform guidance and best practice for future reorganisations.</p>', 'Overview', 45, NULL),
('Workforce diversity and inclusion', '<p>New organisations often take the opportunity to reinforce diversity and inclusion in recruitment and organisational culture.</p>', 'Workforce Impact', 46, NULL),
('Medium-term financial planning', '<p>Medium-term financial plans reflect savings from reorganisation and ongoing cost pressures in the new unitary structure.</p>', 'Financial Performance', 47, NULL),
('Digital and customer strategy', '<p>Unitary councils frequently adopt a single digital and customer strategy to improve access and efficiency across all services.</p>', 'Service Delivery', 48, NULL),
('Local accountability and legitimacy', '<p>Debate continues on how unitary structures can maintain local accountability and legitimacy across larger geographical areas.</p>', 'Democratic Impact', 49, NULL);
